  "py04-digits-average": "from math import ceil\n\ndef digits_average(n):\n    if n > 10:\n        number_cut = n\n        counter = 0\n        digit1 = number_cut % 10\n        digit2 = (number_cut % 100 - digit1) // 10\n        number_cut = number_cut // 10\n        n = ceil((digit1 + digit2) / 2 * 10 ** counter)\n        counter += 1\n        while number_cut > 10:\n            digit1 = number_cut % 10\n            digit2 = (number_cut % 100 - digit1) // 10\n            number_cut = number_cut // 10\n            n += ceil((digit1 + digit2) / 2) * 10 ** counter\n            counter += 1\n        n = digits_average(n)\n    return n",
  "py04-caesar-fibonacci": "from math import sqrt\n\n\ndef caesar(message):\n    answer = \"\"\n    counter = 0\n    for char in message:\n        fibonacci = int(((1 + sqrt(5))**counter - (1 - sqrt(5))**counter) // (2**counter * sqrt(5)))\n        if char.isalpha():\n            answer += shift(char, fibonacci)\n        else:\n            answer += char\n        counter += 1\n    return answer\n\n\ndef shift(character, number):\n    return (chr((ord(character) - number -65) % 26 + 65))",
